//! Brain abstraction: one chat-completion surface over the sovereign backends
//! (skymesh OpenAI-compatible mesh, local fat-station per-token decode, RWKV-7
//! SSM). The agent tool loop and browser-step both decide through a `Brain` so
//! the backend is an env-var choice (`MOONSHINE_AGENT_BRAIN`), not a code path.
//!
//! Child module of `agent_runtime` on purpose: it reuses the parent's mesh
//! decode loop, detokenizer, and text cleanup without widening their
//! visibility.

use anyhow::{anyhow, Result};
use std::time::Duration;
use tokio::time::sleep;

use super::{
    clean_chat_text, default_gen_tokens, detokenize_via_mesh, env_nonempty, fat_station_port,
    generate_via_mesh_opts, is_port_open, strip_think_block, StopMode,
};

/// Default sovereign skymesh OpenAI-compatible chat endpoint (mesh zoo).
pub(crate) const DEFAULT_AGENT_CHAT_URL: &str = "https://skymesh.forkjoin.ai/v1/chat/completions";
/// `15b` = DeepSeek-R1-1.5B: the speed/quality middle ground for decisions.
pub(crate) const DEFAULT_AGENT_CHAT_MODEL: &str = "15b";

/// edgework-app's gated OpenAI-compatible endpoint (`apps/edgework-app/src/
/// app/api/v1/chat/completions/route.ts`) — auth, per-tier rate-limiting,
/// and GPU credit deduction, THEN forwards to the Cloud Run mesh. Used for
/// the "cloud" tier (`/model cloud <id>`) instead of hitting
/// gnosis-openai-mesh directly, so big-model usage is actually metered.
pub(crate) const CLOUD_GATE_CHAT_URL: &str = "https://edgework.ai/api/v1/chat/completions";

/// Resolves an edgework API key for the `Authorization: Bearer` header on
/// every skymesh-leg request (harmless extra header for skymesh.forkjoin.ai
/// and the raw Cloud Run mesh, which don't check it; required by the
/// edgework gate). Same env-var names the TS SDK already documents
/// (`packages/edgework-sdk/src/edgework-api-key.ts`), falling back to a
/// `~/.edgework/api-key` file (mirrors the existing `~/.edgework/agent.ucan`
/// credential-storage convention) so a key doesn't have to live in shell env.
pub(crate) fn edgework_api_key() -> Option<String> {
    for var in ["EDGEWORK_API_KEY", "EDGEWORK_API_TOKEN", "EW_API_KEY"] {
        if let Some(value) = env_nonempty(var) {
            return Some(value);
        }
    }
    let home = std::env::var("HOME").ok()?;
    let path = std::path::Path::new(&home).join(".edgework").join("api-key");
    std::fs::read_to_string(path)
        .ok()
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
}

/// Curated, hand-maintained catalog for `/model list`. Neither backend has a
/// single useful live catalog by default: skymesh (the default chat_url)
/// exposes no `/v1/models` route at all, and the Cloud Run mesh's
/// `/v1/models` only lists anything once `MOONSHINE_AGENT_CHAT_URL` is
/// already pointed at it — so this is printed instead of attempted over the
/// network. Keep in sync with apps/skymesh's model alias table and
/// distributed-inference-host's mesh-model-registry.ts if either changes.
